+    fn accept(&self, cx: &Cx) -> Result<(TcpStream, SocketAddr)> {
+        loop {
+            cx.checkpoint().map_err(|_| FfsError::Cancelled)?;
+            if budget_expired(cx) {
+                return Err(FfsError::Cancelled);
+            }
