+            match self.listener.accept() {
+                Ok(pair) => return Ok(pair),
+                Err(err) if err.kind() == std::io::ErrorKind::WouldBlock => {
+                    sleep_with_budget(cx, self.config.accept_poll_interval)?;
+                }
+                Err(err) => return Err(FfsError::from(err)),
+            }
+        }
+    }
